const data = $input.first().json.output;

// Safeguard
const safe = v => (v === undefined || v === null ? "unknown" : v);

// Format time to HH:MM:SS
const fixTime = (t) => {
  if (!t) return "unknown";
  if (t.length === 8) return t;
  const d = new Date(t);
  if (isNaN(d)) return t;
  return d.toISOString().substring(11,19);
};

// List formatter
const list = (arr, fmt) => {
  if (!arr || arr.length === 0) return "(none)";
  return arr.map(fmt).join("\n");
};

// Build final report text (NO EMBED)
let message =
`🚨 **Honeypot Attacker Session Report**
────────────────────────────────────

**🆔 Session ID:** \`${safe(data.session_id)}\`
**🌐 IP:** \`${safe(data.ip)}\`
**⏳ Duration:** ${fixTime(data.start_time)} ➝ ${fixTime(data.end_time)}
**💥 Threat Level:** ${safe(data.threat_level)}

### 📝 Session Summary
${safe(data.session_summary)}

### 🎯 Attacker Intent
**${safe(data.attacker_intent)}**

### ⚠️ Suspicious Commands
${list(data.suspicious_commands, (c, i) => `**${i+1}.** \`${c.cmd}\` — ${c.reason}`)}

### 👀 Behavior Analysis
${safe(data.behavior_analysis)}

### 🕒 Timeline
${list(data.timeline, (t, i) => `**${i+1}.** \`${fixTime(t.time)}\`\n➡️ ${t.action}`)}

### 🛡️ Recommendations
${list(data.recommendations, (r, i) => `**${i+1}.** ${r}`)}`;


// ========== DISCORD HARD LIMIT FIX ==========
const MAX = 1800;
let chunks = [];

while (message.length > MAX) {
  chunks.push(message.slice(0, MAX));
  message = message.slice(MAX);
}
chunks.push(message);

return chunks.map(c => ({
  json: { content: c }
}));

