const data = $input.first().json.output;

// Helper untuk value aman
function clean(v, fallback = "(unknown)") {
    if (v === undefined || v === null) return fallback;
    if (typeof v === "string" && v.trim() === "-") return fallback;
    if (typeof v === "string" && v.trim() === "") return fallback;
    return v;
}

// Format list
function formatList(arr) {
    if (!Array.isArray(arr)) return "-";
    return arr.map((x, i) => `**${i + 1}.** ${x}`).join("\n");
}

// Format timeline
function formatTimeline(arr) {
    if (!Array.isArray(arr)) return "-";
    return arr
        .map((x, i) => {
            const t = clean(x.time, "(no time)");
            const e = clean(x.event, "(no event)");
            return `**${i + 1}.** \`${t}\`\n➡️ ${e}`;
        })
        .join("\n\n");
}

// Extract attacker profile safely
const profile = data.attacker_profile || {};

const message =
`🚨 **Attacker Behavior Analysis Report**
────────────────────────────────────

### 🌐 IP Address
\`${clean(data.ip)}\`

### 🎯 Attack Type
**${clean(data.attack_type)}**

### 💥 Threat Level
**${clean(data.threat_level).toUpperCase()}**

## 🧠 Behavior Summary
${clean(data.behavior_summary)}

## 🧬 Attacker Profile
- **Automation:** ${clean(profile.automation)}
- **Speed:** ${clean(profile.speed)}
- **Username Pattern:** ${clean(profile.username_pattern)}
- **Password Pattern:** ${clean(profile.password_pattern)}

## 🕒 Timeline
${formatTimeline(data.timeline)}

## 🔍 Indicators
${formatList(data.indicators)}

## 🛡️ Recommendations
${formatList(data.recommendations)}`;

return [{ json: { message } }];
